  1→import {
  2→  Search,
  3→  CheckSquare,
  4→  Square,
  5→  MinusSquare,
  6→  Clock,
  7→  FolderOpen,
  8→  ChevronDown,
  9→  ChevronRight,
 10→} from "lucide-react";
 11→import { useMemo, useState } from "react";
 12→import type { Trajectory } from "../types";
 13→import { formatTime, truncate, baseProjectName } from "../utils";
 14→
 15→export type ViewMode = "time" | "project";
 16→
 17→interface SessionListProps {
 18→  sessions: Trajectory[];
 19→  selectedId: string | null;
 20→  onSelect: (id: string) => void;
 21→  checkedIds: Set<string>;
 22→  onCheckedChange: (ids: Set<string>) => void;
 23→  viewMode: ViewMode;
 24→  onViewModeChange: (mode: ViewMode) => void;
 25→}
 26→
 27→export function SessionList({
 28→  sessions,
 29→  selectedId,
 30→  onSelect,
 31→  checkedIds,
 32→  onCheckedChange,
 33→  viewMode,
 34→  onViewModeChange,
 35→}: SessionListProps) {
 36→  const [search, setSearch] = useState("");
 37→  const [expandedProjects, setExpandedProjects] = useState<Set<string>>(
 38→    new Set()
 39→  );
 40→
 41→  const filtered = sessions.filter((s) => {
 42→    if (!search) return true;
 43→    const q = search.toLowerCase();
 44→    return (
 45→      (s.first_message || "").toLowerCase().includes(q) ||
 46→      (s.project_path || "").toLowerCase().includes(q)
 47→    );
 48→  });
 49→
 50→  const filteredIds = new Set(filtered.map((s) => s.session_id));
 51→  const checkedInView = [...checkedIds].filter((id) => filteredIds.has(id));
 52→  const allChecked =
 53→    filtered.length > 0 && checkedInView.length === filtered.length;
 54→  const someChecked = checkedInView.length > 0 && !allChecked;
 55→
 56→  const groupedByProject = useMemo(() => {
 57→    const groups = new Map<string, Trajectory[]>();
 58→    for (const session of filtered) {
 59→      const key = session.project_path || "Unknown";
 60→      const list = groups.get(key) || [];
 61→      list.push(session);
 62→      groups.set(key, list);
 63→    }
 64→    return groups;
 65→  }, [filtered]);
 66→
 67→  const handleSetViewMode = (mode: ViewMode) => {
 68→    if (mode === "project" && viewMode !== "project") {
 69→      setExpandedProjects(new Set());
 70→    }
 71→    onViewModeChange(mode);
 72→  };
 73→
 74→  const toggleProjectExpanded = (projectName: string) => {
 75→    const next = new Set(expandedProjects);
 76→    if (next.has(projectName)) {
 77→      next.delete(projectName);
 78→    } else {
 79→      next.add(projectName);
 80→    }
 81→    setExpandedProjects(next);
 82→  };
 83→
 84→  const handleToggleAll = () => {
 85→    if (allChecked) {
 86→      const next = new Set(checkedIds);
 87→      for (const s of filtered) next.delete(s.session_id);
 88→      onCheckedChange(next);
 89→    } else {
 90→      const next = new Set(checkedIds);
 91→      for (const s of filtered) next.add(s.session_id);
 92→      onCheckedChange(next);
 93→    }
 94→  };
 95→
 96→  const handleToggleOne = (sessionId: string) => {
 97→    const next = new Set(checkedIds);
 98→    if (next.has(sessionId)) {
 99→      next.delete(sessionId);
100→    } else {
101→      next.add(sessionId);
102→    }
103→    onCheckedChange(next);
104→  };
105→
106→  return (
107→    <div className="flex flex-col flex-1 min-h-0">
108→      <div className="p-3 space-y-2 border-b border-zinc-800">
109→        {/* View Mode Toggle */}
110→        <div className="flex gap-0.5 bg-zinc-800 rounded p-0.5">
111→          <button
112→            onClick={() => handleSetViewMode("project")}
113→            className={`flex-1 flex items-center justify-center gap-1.5 text-xs py-1.5 rounded transition ${
114→              viewMode === "project"
115→                ? "bg-zinc-700 text-zinc-100"
116→                : "text-zinc-500 hover:text-zinc-300"
117→            }`}
118→          >
119→            <FolderOpen className="w-3.5 h-3.5" />
120→            By Project
121→          </button>
122→          <button
123→            onClick={() => handleSetViewMode("time")}
124→            className={`flex-1 flex items-center justify-center gap-1.5 text-xs py-1.5 rounded transition ${
125→              viewMode === "time"
126→                ? "bg-zinc-700 text-zinc-100"
127→                : "text-zinc-500 hover:text-zinc-300"
128→            }`}
129→          >
130→            <Clock className="w-3.5 h-3.5" />
131→            By Time
132→          </button>
133→        </div>
134→
135→        <div className="relative">
136→          <Search className="absolute left-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-zinc-500" />
137→          <input
138→            type="text"
139→            placeholder="Search sessions..."
140→            value={search}
141→            onChange={(e) => setSearch(e.target.value)}
142→            className="w-full bg-zinc-800 text-zinc-200 text-sm rounded pl-7 pr-2 py-1.5 border border-zinc-700 focus:outline-none focus:border-cyan-600 placeholder:text-zinc-500"
143→          />
144→        </div>
145→
146→        {/* Select All */}
147→        <button
148→          onClick={handleToggleAll}
149→          className="flex items-center gap-1.5 text-[11px] text-zinc-400 hover:text-zinc-200 transition"
150→        >
151→          {allChecked ? (
152→            <CheckSquare className="w-3.5 h-3.5 text-cyan-400" />
153→          ) : someChecked ? (
154→            <MinusSquare className="w-3.5 h-3.5 text-cyan-400" />
155→          ) : (
156→            <Square className="w-3.5 h-3.5" />
157→          )}
158→          Select all ({filtered.length})
159→        </button>
160→      </div>
161→
162→      <div className="flex-1 overflow-y-auto">
163→        {viewMode === "time" ? (
164→          filtered.map((session) => (
165→            <SessionRow
166→              key={session.session_id}
167→              session={session}
168→              selectedId={selectedId}
169→              checkedIds={checkedIds}
170→              onSelect={onSelect}
171→              onToggle={handleToggleOne}
172→            />
173→          ))
174→        ) : (
175→          Array.from(groupedByProject.entries()).map(
176→            ([projectName, projectSessions]) => {
177→              const projectIds = projectSessions.map((s) => s.session_id);
178→              const allProjectChecked = projectIds.every((id) =>
179→                checkedIds.has(id)
180→              );
181→              const someProjectChecked =
182→                !allProjectChecked &&
183→                projectIds.some((id) => checkedIds.has(id));
184→              const handleToggleProject = (e: React.MouseEvent) => {
185→                e.stopPropagation();
186→                const next = new Set(checkedIds);
187→                if (allProjectChecked) {
188→                  for (const id of projectIds) next.delete(id);
189→                } else {
190→                  for (const id of projectIds) next.add(id);
191→                }
192→                onCheckedChange(next);
193→              };
194→              return (
195→              <div key={projectName}>
196→                <div className="sticky top-0 z-10 w-full flex items-center gap-1 bg-zinc-900 border-b border-zinc-800 text-xs text-zinc-300">
197→                  <button
198→                    onClick={handleToggleProject}
199→                    className="shrink-0 pl-3 pr-1 py-2 text-zinc-500 hover:text-cyan-400 transition"
200→                    title={allProjectChecked ? "Deselect project" : "Select project"}
201→                  >
202→                    {allProjectChecked ? (
203→                      <CheckSquare className="w-3.5 h-3.5 text-cyan-400" />
204→                    ) : someProjectChecked ? (
205→                      <MinusSquare className="w-3.5 h-3.5 text-cyan-400" />
206→                    ) : (
207→                      <Square className="w-3.5 h-3.5" />
208→                    )}
209→                  </button>
210→                  <button
211→                    onClick={() => toggleProjectExpanded(projectName)}
212→                    className="flex-1 flex items-center gap-2 pr-3 py-2 hover:text-zinc-100 transition min-w-0"
213→                  >
214→                    {expandedProjects.has(projectName) ? (
215→                      <ChevronDown className="w-3.5 h-3.5 shrink-0" />
216→                    ) : (
217→                      <ChevronRight className="w-3.5 h-3.5 shrink-0" />
218→                    )}
219→                    <FolderOpen className="w-3.5 h-3.5 shrink-0 text-zinc-500" />
220→                    <span className="truncate font-medium" title={projectName}>
221→                      {baseProjectName(projectName)}
222→                    </span>
223→                    <span className="ml-auto text-zinc-500 shrink-0">
224→                      {projectSessions.length}
225→                    </span>
226→                  </button>
227→                </div>
228→                {expandedProjects.has(projectName) &&
229→                  projectSessions.map((session) => (
230→                    <SessionRow
231→                      key={session.session_id}
232→                      session={session}
233→                      selectedId={selectedId}
234→                      checkedIds={checkedIds}
235→                      onSelect={onSelect}
236→                      onToggle={handleToggleOne}
237→                    />
238→                  ))}
239→              </div>
240→              );
241→            })
242→        )}
243→      </div>
244→    </div>
245→  );
246→}
247→
248→function SessionRow({
249→  session,
250→  selectedId,
251→  checkedIds,
252→  onSelect,
253→  onToggle,
254→}: {
255→  session: Trajectory;
256→  selectedId: string | null;
257→  checkedIds: Set<string>;
258→  onSelect: (id: string) => void;
259→  onToggle: (id: string) => void;
260→}) {
261→  return (
262→    <div
263→      className={`flex items-start border-b border-zinc-800/50 transition-all duration-200 ${
264→        selectedId === session.session_id
265→          ? "bg-cyan-600/15 border-l-2 border-l-cyan-400"
266→          : "hover:bg-zinc-800/50 border-l-2 border-l-transparent"
267→      }`}
268→    >
269→      {/* Checkbox */}
270→      <button
271→        onClick={(e) => {
272→          e.stopPropagation();
273→          onToggle(session.session_id);
274→        }}
275→        className="shrink-0 px-2 pt-3 text-zinc-500 hover:text-cyan-400 transition"
276→      >
277→        {checkedIds.has(session.session_id) ? (
278→          <CheckSquare className="w-3.5 h-3.5 text-cyan-400" />
279→        ) : (
280→          <Square className="w-3.5 h-3.5" />
281→        )}
282→      </button>
283→
284→      {/* Session content */}
285→      <button
286→        onClick={() => onSelect(session.session_id)}
287→        className="flex-1 text-left pr-3 py-2.5 min-w-0"
288→      >
289→        <div className="flex items-center justify-between mb-0.5">
290→          <span className="text-[10px] text-zinc-500 uppercase tracking-wide" title={session.project_path || ""}>
291→            {baseProjectName(session.project_path || "")}
292→          </span>
293→          <span className="text-[10px] text-zinc-500">
294→            {formatTime(session.timestamp ?? null)}
295→          </span>
296→        </div>
297→        <p className="text-xs text-zinc-300 line-clamp-2 leading-relaxed">
298→          {truncate(session.first_message || "", 120) || "Empty session"}
299→        </p>
300→      </button>
301→    </div>
302→  );
303→}
