 1→const MINUTE = 60;
 2→const HOUR = 3600;
 3→const DAY = 86400;
 4→
 5→export function formatTime(timestamp: string | null): string {
 6→  if (!timestamp) return "";
 7→  const diff = Math.floor((Date.now() - new Date(timestamp).getTime()) / 1000);
 8→  if (diff < MINUTE) return "now";
 9→  if (diff < HOUR) return `${Math.floor(diff / MINUTE)}m`;
10→  if (diff < DAY) return `${Math.floor(diff / HOUR)}h`;
11→  return `${Math.floor(diff / DAY)}d`;
12→}
13→
14→const SYSTEM_TAG_RE = /<(?:system-reminder|command-name|command-message|user-prompt-submit-hook|local-command-caveat|local-command-stdout|task-notification)[^>]*>[\s\S]*?<\/(?:system-reminder|command-name|command-message|user-prompt-submit-hook|local-command-caveat|local-command-stdout|task-notification)>/g;
15→
16→export function sanitizeText(text: string): string {
17→  return text.replace(SYSTEM_TAG_RE, "").trim();
18→}
19→
20→export function truncate(text: string, max: number): string {
21→  if (text.length <= max) return text;
22→  return text.slice(0, max) + "...";
23→}
24→
25→export function formatTokens(n: number): string {
26→  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
27→  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
28→  return String(n);
29→}
30→
31→export function formatDuration(seconds: number | null | undefined): string {
32→  if (!seconds || seconds <= 0) return "0s";
33→  const hours = Math.floor(seconds / HOUR);
34→  const minutes = Math.floor((seconds % HOUR) / MINUTE);
35→  const secs = Math.floor(seconds % MINUTE);
36→  const parts: string[] = [];
37→  if (hours > 0) parts.push(`${hours}h`);
38→  if (minutes > 0) parts.push(`${minutes}m`);
39→  if (secs > 0 || parts.length === 0) parts.push(`${secs}s`);
40→  return parts.join(" ");
41→}
42→
43→export function extractUserText(step: { message: string }): string {
44→  return sanitizeText(step.message);
45→}
46→
47→export function baseProjectName(path: string): string {
48→  if (!path) return "Unknown";
49→  const normalized = path.replace(/[\\/]+$/, "");
50→  const segments = normalized.split(/[\\/]/).filter(Boolean);
51→  const LAST_N_SEGMENTS = 2;
52→  if (segments.length === 0) return path;
53→  const tail = segments.slice(-LAST_N_SEGMENTS);
54→  return tail.join("/");
55→}
56→
57→export function formatElapsed(totalSeconds: number): string {
58→  const hours = Math.floor(totalSeconds / HOUR);
59→  const minutes = Math.floor((totalSeconds % HOUR) / MINUTE);
60→  const seconds = Math.floor(totalSeconds % MINUTE);
61→  if (hours > 0) {
62→    return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
63→  }
64→  return `${minutes}:${String(seconds).padStart(2, "0")}`;
65→}
