  1→import {
  2→  Menu,
  3→  PanelLeftClose,
  4→  ChevronUp,
  5→  ChevronDown,
  6→  Download,
  7→  FileUp,
  8→  Heart,
  9→} from "lucide-react";
 10→import { useEffect, useState, useCallback, createContext, useContext } from "react";
 11→import { ConfirmDialog } from "./components/confirm-dialog";
 12→import { DonateConsentDialog } from "./components/donate-consent-dialog";
 13→import { ResizeHandle } from "./components/resize-handle";
 14→import { SessionList, type ViewMode } from "./components/session-list";
 15→import { SessionView } from "./components/session-view";
 16→import { UploadDialog } from "./components/upload-dialog";
 17→import type { DonateResult, Trajectory } from "./types";
 18→
 19→type AppMode = "self" | "demo";
 20→
 21→type DialogState =
 22→  | { kind: "hidden" }
 23→  | { kind: "donate-confirm" }
 24→  | { kind: "donating" }
 25→  | { kind: "donate-result"; result: DonateResult };
 26→
 27→interface AppContextValue {
 28→  sessionToken: string;
 29→  appMode: AppMode;
 30→  maxZipBytes: number;
 31→  fetchWithToken: (url: string, init?: RequestInit) => Promise<Response>;
 32→}
 33→
 34→const DEFAULT_MAX_ZIP_BYTES = 500 * 1024 * 1024;
 35→
 36→const AppContext = createContext<AppContextValue>({
 37→  sessionToken: "",
 38→  appMode: "self",
 39→  maxZipBytes: DEFAULT_MAX_ZIP_BYTES,
 40→  fetchWithToken: (url, init) => fetch(url, init),
 41→});
 42→
 43→export function useAppContext(): AppContextValue {
 44→  return useContext(AppContext);
 45→}
 46→
 47→export function App() {
 48→  const [sidebarOpen, setSidebarOpen] = useState(true);
 49→  const [sessions, setSessions] = useState<Trajectory[]>([]);
 50→  const [projects, setProjects] = useState<string[]>([]);
 51→  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(
 52→    null
 53→  );
 54→  const [page, setPage] = useState(0);
 55→  const [loading, setLoading] = useState(false);
 56→  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
 57→  const [dialog, setDialog] = useState<DialogState>({ kind: "hidden" });
 58→  const [showUploadDialog, setShowUploadDialog] = useState(false);
 59→  const [refreshKey, setRefreshKey] = useState(0);
 60→  const [viewMode, setViewMode] = useState<ViewMode>("project");
 61→  const [sidebarWidth, setSidebarWidth] = useState(320);
 62→  const [appMode, setAppMode] = useState<AppMode>("self");
 63→  const [maxZipBytes, setMaxZipBytes] = useState(DEFAULT_MAX_ZIP_BYTES);
 64→
 65→
 66→  // Ephemeral token: new on every page load, never persisted
 67→  const [sessionToken] = useState(() =>
 68→    crypto.randomUUID?.() ??
 69→    Array.from(crypto.getRandomValues(new Uint8Array(16)), (b) => b.toString(16).padStart(2, "0")).join("")
 70→  );
 71→
 72→  const MIN_SIDEBAR_WIDTH = 240;
 73→  const MAX_SIDEBAR_WIDTH = 600;
 74→  const SESSIONS_PER_PAGE = 100;
 75→
 76→  const fetchWithToken = useCallback(
 77→    (url: string, init?: RequestInit): Promise<Response> => {
 78→      const headers = new Headers(init?.headers);
 79→      headers.set("X-Session-Token", sessionToken);
 80→      return fetch(url, { ...init, headers });
 81→    },
 82→    [sessionToken]
 83→  );
 84→
 85→  const contextValue: AppContextValue = {
 86→    sessionToken,
 87→    appMode,
 88→    maxZipBytes,
 89→    fetchWithToken,
 90→  };
 91→
 92→  const handleSidebarResize = useCallback((delta: number) => {
 93→    setSidebarWidth((w) =>
 94→      Math.min(MAX_SIDEBAR_WIDTH, Math.max(MIN_SIDEBAR_WIDTH, w + delta))
 95→    );
 96→  }, []);
 97→
 98→  // Fetch app mode on mount
 99→  useEffect(() => {
100→    fetchWithToken("/api/settings")
101→      .then((r) => r.json())
102→      .then((data: { app_mode?: string; max_zip_bytes?: number }) => {
103→        if (data.app_mode === "demo") setAppMode("demo");
104→        if (data.max_zip_bytes) setMaxZipBytes(data.max_zip_bytes);
105→      })
106→      .catch((err) => console.error("Failed to load settings:", err));
107→  }, [fetchWithToken]);
108→
109→  useEffect(() => {
110→    fetchWithToken("/api/projects")
111→      .then((r) => r.json())
112→      .then((data: string[]) => setProjects(data))
113→      .catch((err) => console.error("Failed to load projects:", err));
114→  }, [fetchWithToken, refreshKey]);
115→
116→  useEffect(() => {
117→    setLoading(true);
118→    const params = new URLSearchParams();
119→    params.set("limit", String(SESSIONS_PER_PAGE));
120→    params.set("offset", String(page * SESSIONS_PER_PAGE));
121→
122→    fetchWithToken(`/api/sessions?${params}`)
123→      .then((r) => r.json())
124→      .then((data: Trajectory[]) => setSessions(data))
125→      .catch((err) => console.error("Failed to load sessions:", err))
126→      .finally(() => setLoading(false));
127→  }, [page, refreshKey, fetchWithToken]);
128→
129→  const handleSelectSession = useCallback((id: string | null) => {
130→    setSelectedSessionId(id);
131→  }, []);
132→
133→  const handleDownloadClick = async () => {
134→    if (checkedIds.size === 0) return;
135→    try {
136→      const res = await fetchWithToken("/api/sessions/download", {
137→        method: "POST",
138→        headers: { "Content-Type": "application/json" },
139→        body: JSON.stringify({ session_ids: [...checkedIds] }),
140→      });
141→      if (!res.ok) return;
142→      const blob = await res.blob();
143→      const url = URL.createObjectURL(blob);
144→      const a = document.createElement("a");
145→      a.href = url;
146→      a.download = "vibelens-export.zip";
147→      a.click();
148→      URL.revokeObjectURL(url);
149→    } catch (err) {
150→      console.error("Download failed:", err);
151→    }
152→  };
153→
154→  const handleDonateClick = () => {
155→    if (checkedIds.size === 0) return;
156→    setDialog({ kind: "donate-confirm" });
157→  };
158→
159→  const handleDonateConfirm = useCallback(async () => {
160→    setDialog({ kind: "donating" });
161→    try {
162→      const res = await fetchWithToken("/api/sessions/donate", {
163→        method: "POST",
164→        headers: { "Content-Type": "application/json" },
165→        body: JSON.stringify({ session_ids: [...checkedIds] }),
166→      });
167→      if (!res.ok) {
168→        let errorMsg = `HTTP ${res.status}`;
169→        try {
170→          const body = await res.json();
171→          errorMsg = body.detail || JSON.stringify(body);
172→        } catch {
173→          errorMsg = await res.text().catch(() => errorMsg);
174→        }
175→        setDialog({
176→          kind: "donate-result",
177→          result: {
178→            total: checkedIds.size,
179→            donated: 0,
180→            errors: [{ session_id: "", error: errorMsg }],
181→          },
182→        });
183→        return;
184→      }
185→      const result: DonateResult = await res.json();
186→      setDialog({ kind: "donate-result", result });
187→    } catch (err) {
188→      setDialog({
189→        kind: "donate-result",
190→        result: {
191→          total: checkedIds.size,
192→          donated: 0,
193→          errors: [{ session_id: "", error: String(err) }],
194→        },
195→      });
196→    }
197→  }, [checkedIds, fetchWithToken]);
198→
199→  const handleDialogClose = () => {
200→    if (dialog.kind === "donate-result" && dialog.result.donated > 0) {
201→      setCheckedIds(new Set());
202→    }
203→    setDialog({ kind: "hidden" });
204→  };
205→
206→  const renderDialog = () => {
207→    switch (dialog.kind) {
208→      case "donate-confirm":
209→        return (
210→          <DonateConsentDialog
211→            sessionCount={checkedIds.size}
212→            onConfirm={handleDonateConfirm}
213→            onCancel={handleDialogClose}
214→          />
215→        );
216→      case "donating":
217→        return (
218→          <ConfirmDialog
219→            title="Donating..."
220→            message={`Donating ${checkedIds.size} session${checkedIds.size !== 1 ? "s" : ""}...`}
221→            onConfirm={() => {}}
222→            onCancel={() => {}}
223→            loading
224→          />
225→        );
226→      case "donate-result": {
227→        const dr = dialog.result;
228→        const hasDonateErrors = dr.errors.length > 0;
229→        const donateLines = [
230→          `Donated: ${dr.donated}`,
231→          `Total: ${dr.total}`,
232→        ];
233→        if (hasDonateErrors) {
234→          donateLines.push("");
235→          donateLines.push(`Errors: ${dr.errors.length}`);
236→          for (const e of dr.errors.slice(0, 3)) {
237→            donateLines.push(`  ${e.session_id || "—"}: ${e.error}`);
238→          }
239→        }
240→        return (
241→          <ConfirmDialog
242→            title={hasDonateErrors ? "Completed with errors" : "Donation complete"}
243→            message={donateLines.join("\n")}
244→            confirmLabel="OK"
245→            cancelLabel="Close"
246→            onConfirm={handleDialogClose}
247→            onCancel={handleDialogClose}
248→          />
249→        );
250→      }
251→      default:
252→        return null;
253→    }
254→  };
255→
256→  return (
257→    <AppContext.Provider value={contextValue}>
258→      <div className="flex h-screen overflow-hidden bg-zinc-950 text-zinc-100">
259→        {/* Sidebar */}
260→        {sidebarOpen && (
261→          <aside
262→            style={{ width: sidebarWidth }}
263→            className="relative border-r border-zinc-800 flex flex-col shrink-0 bg-zinc-900"
264→          >
265→            <ResizeHandle side="left" onResize={handleSidebarResize} />
266→            <div className="flex items-center justify-between px-4 h-[75px] border-b border-zinc-800 sticky top-0">
267→              <div className="flex items-center gap-3">
268→                <img src="/icon.png" alt="VibeLens" className="w-12 h-12" />
269→                <h1 className="text-2xl font-bold text-cyan-400">VibeLens</h1>
270→              </div>
271→              <button
272→                onClick={() => setSidebarOpen(false)}
273→                className="text-zinc-500 hover:text-zinc-300 transition"
274→                title="Collapse sidebar"
275→              >
276→                <PanelLeftClose className="w-4 h-4" />
277→              </button>
278→            </div>
279→
280→            {/* Toolbar */}
281→            <div className="shrink-0 border-b border-zinc-800 px-3 py-2.5 grid grid-cols-3 gap-2 text-xs text-zinc-400">
282→              <button
283→                onClick={() => setShowUploadDialog(true)}
284→                className="flex items-center justify-center gap-1.5 py-1.5 text-xs font-medium bg-violet-600 hover:bg-violet-500 text-white rounded transition"
285→                title="Upload conversation files"
286→              >
287→                <FileUp className="w-3.5 h-3.5" />
288→                Upload
289→              </button>
290→              <button
291→                onClick={handleDownloadClick}
292→                disabled={checkedIds.size === 0}
293→                className="flex items-center justify-center gap-1.5 py-1.5 text-xs font-medium bg-emerald-600 hover:bg-emerald-500 text-white rounded transition disabled:opacity-40 disabled:cursor-not-allowed"
294→                title="Download selected sessions as zip"
295→              >
296→                <Download className="w-3.5 h-3.5" />
297→                Download
298→              </button>
299→              <button
300→                onClick={handleDonateClick}
301→                disabled={checkedIds.size === 0}
302→                className="flex items-center justify-center gap-1.5 py-1.5 text-xs font-medium bg-rose-600 hover:bg-rose-500 text-white rounded transition disabled:opacity-40 disabled:cursor-not-allowed"
303→                title="Donate selected sessions for research"
304→              >
305→                <Heart className="w-3.5 h-3.5" />
306→                Donate
307→              </button>
308→            </div>
309→
310→            <SessionList
311→              sessions={sessions}
312→              selectedId={selectedSessionId}
313→              onSelect={handleSelectSession}
314→              checkedIds={checkedIds}
315→              onCheckedChange={setCheckedIds}
316→              viewMode={viewMode}
317→              onViewModeChange={setViewMode}
318→            />
319→
320→            {/* Footer: Session count + Pagination */}
321→            <div className="shrink-0 border-t border-zinc-800 px-3 py-2 flex items-center justify-between text-xs text-zinc-400">
322→              <span>{sessions.length} sessions</span>
323→              {viewMode === "time" && (
324→                <div className="flex items-center gap-1">
325→                  <button
326→                    onClick={() => setPage(Math.max(0, page - 1))}
327→                    disabled={page === 0 || loading}
328→                    className="p-1 hover:bg-zinc-800 disabled:opacity-50 disabled:cursor-not-allowed rounded transition"
329→                    title="Previous page"
330→                  >
331→                    <ChevronUp className="w-4 h-4" />
332→                  </button>
