 29→export function SessionView({ sessionId }: SessionViewProps) {
 30→  const { fetchWithToken } = useAppContext();
 31→  const [trajectories, setTrajectories] = useState<Trajectory[]>([]);
 32→  const [loading, setLoading] = useState(true);
 33→  const [error, setError] = useState("");
 34→  const [activeStepId, setActiveStepId] = useState<string | null>(null);
 35→  const [promptNavWidth, setPromptNavWidth] = useState(224);
 36→  const [sessionCost, setSessionCost] = useState<number | null>(null);
 37→  const stepsRef = useRef<HTMLDivElement>(null);
 38→  const isNavigatingRef = useRef(false);
 39→
 40→  const MIN_PROMPT_NAV_WIDTH = 160;
 41→  const MAX_PROMPT_NAV_WIDTH = 400;
 42→
 43→  const handlePromptNavResize = useCallback((delta: number) => {
 44→    setPromptNavWidth((w) =>
 45→      Math.min(MAX_PROMPT_NAV_WIDTH, Math.max(MIN_PROMPT_NAV_WIDTH, w + delta))
 46→    );
 47→  }, []);
 48→
 49→  useEffect(() => {
 50→    setLoading(true);
 51→    setError("");
 52→    setTrajectories([]);
 53→    setActiveStepId(null);
 54→    setSessionCost(null);
 55→
 56→    fetchWithToken(`/api/sessions/${sessionId}`)
 57→      .then((res) => {
 58→        if (!res.ok) throw new Error(`Failed to load session: ${res.status}`);
 59→        return res.json();
 60→      })
 61→      .then((data: Trajectory[]) => {
 62→        setTrajectories(data);
 63→      })
 64→      .catch((err: Error) => setError(err.message))
 65→      .finally(() => setLoading(false));
 66→  }, [sessionId, fetchWithToken]);
 67→
 68→  // Fetch session analytics for cost estimation (non-blocking)
 69→  useEffect(() => {
 70→    if (!sessionId || loading) return;
 71→    fetchWithToken(`/api/analysis/sessions/${sessionId}/stats`)
 72→      .then((res) => (res.ok ? res.json() : null))
 73→      .then((data) => {
 74→        if (data?.cost_usd != null) setSessionCost(data.cost_usd);
 75→      })
 76→      .catch(() => {});
 77→  }, [sessionId, loading, fetchWithToken]);
 78→
 79→  const main = useMemo(
 80→    () => trajectories.find((t) => !t.parent_trajectory_ref) ?? trajectories[0] ?? null,
 81→    [trajectories]
 82→  );
 83→
 84→  const subAgents = useMemo(
 85→    () =>
 86→      trajectories
 87→        .filter((t) => !!t.parent_trajectory_ref)
 88→        .sort((a, b) => {
 89→          const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
 90→          const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
 91→          return ta - tb;
 92→        }),
 93→    [trajectories]
 94→  );
 95→
 96→  // Build a map: step_id -> sub-agent trajectories spawned from that step.
 97→  // Phase 1 links via observation.subagent_trajectory_ref (explicit linkage).
 98→  // Phase 2 places unlinked sub-agents (e.g. compaction) at the
 99→  // chronologically correct position using timestamp heuristics.
100→  const subAgentsByStep = useMemo(() => {
101→    const map = new Map<string, Trajectory[]>();
102→    const orphans: Trajectory[] = [];
103→    const unlinked: Trajectory[] = [];
104→
105→    for (const sub of subAgents) {
106→      let placed = false;
107→      if (main?.steps) {
108→        for (const step of main.steps) {
109→          if (!step.observation) continue;
110→          for (const result of step.observation.results) {
111→            if (!result.subagent_trajectory_ref) continue;
112→            for (const ref of result.subagent_trajectory_ref) {
113→              if (ref.session_id === sub.session_id) {
114→                const existing = map.get(step.step_id) || [];
115→                existing.push(sub);
116→                map.set(step.step_id, existing);
117→                placed = true;
118→                break;
119→              }
120→            }
121→            if (placed) break;
122→          }
123→          if (placed) break;
124→        }
125→      }
126→      if (!placed) unlinked.push(sub);
127→    }
128→
129→    // Place unlinked sub-agents at the last main step whose timestamp
130→    // is <= the sub-agent's start timestamp. Falls back to orphans
131→    // only when no timestamp is available.
132→    for (const sub of unlinked) {
133→      const subTs = sub.timestamp ? new Date(sub.timestamp).getTime() : NaN;
134→      if (!isNaN(subTs) && main?.steps) {
135→        let bestStepId: string | null = null;
136→        for (const step of main.steps) {
137→          if (!step.timestamp) continue;
138→          const stepTs = new Date(step.timestamp).getTime();
139→          if (stepTs <= subTs) bestStepId = step.step_id;
140→          else break;
141→        }
142→        if (bestStepId) {
143→          const existing = map.get(bestStepId) || [];
144→          existing.push(sub);
145→          map.set(bestStepId, existing);
146→          continue;
147→        }
148→      }
149→      orphans.push(sub);
150→    }
151→
152→    return { map, orphans };
153→  }, [main, subAgents]);
154→
155→  const steps = (main?.steps || []) as Step[];
156→
157→  const userStepIds = useMemo(() => {
158→    return steps
159→      .filter((s) => s.source === "user" && extractUserText(s))
160→      .map((s) => s.step_id);
161→  }, [steps]);
162→
163→  // IntersectionObserver to track which user prompt is currently visible
164→  useEffect(() => {
165→    if (!stepsRef.current || userStepIds.length < 2) return;
166→
167→    const observer = new IntersectionObserver(
168→      (entries) => {
169→        if (isNavigatingRef.current) return;
170→        let topEntry: IntersectionObserverEntry | null = null;
171→        for (const entry of entries) {
172→          if (!entry.isIntersecting) continue;
173→          if (!topEntry || entry.boundingClientRect.top < topEntry.boundingClientRect.top) {
174→            topEntry = entry;
175→          }
176→        }
177→        if (topEntry) {
178→          setActiveStepId(topEntry.target.id.replace("step-", ""));
179→        }
180→      },
181→      {
182→        root: stepsRef.current,
183→        rootMargin: "-10% 0px -80% 0px",
184→        threshold: 0,
185→      }
186→    );
187→
188→    for (const stepId of userStepIds) {
189→      const el = document.getElementById(`step-${stepId}`);
190→      if (el) observer.observe(el);
191→    }
192→
193→    return () => observer.disconnect();
194→  }, [userStepIds]);
