  1→import { useState, useMemo, useCallback, useRef } from "react";
  2→import type { DailyStat } from "../../types";
  3→import { formatTokens, formatCost } from "../../utils";
  4→import type { ChartMetric, TimeGroup } from "./chart-utils";
  5→import { fillDateGaps, groupDailyStats } from "./chart-utils";
  6→
  7→interface UsageOverTimeChartProps {
  8→  data: DailyStat[];
  9→  onHover: (e: React.MouseEvent, text: string) => void;
 10→  onMove: (e: React.MouseEvent) => void;
 11→  onLeave: () => void;
 12→}
 13→
 14→const W = 800;
 15→const H = 200;
 16→const ML = 55;
 17→const MR = 15;
 18→const MT = 12;
 19→const MB = 28;
 20→const PW = W - ML - MR;
 21→const PH = H - MT - MB;
 22→
 23→export function UsageOverTimeChart({
 24→  data,
 25→  onHover,
 26→  onMove,
 27→  onLeave,
 28→}: UsageOverTimeChartProps) {
 29→  const [metric, setMetric] = useState<ChartMetric>("sessions");
 30→  const [timeGroup, setTimeGroup] = useState<TimeGroup>("day");
 31→  const [activeIndex, setActiveIndex] = useState<number | null>(null);
 32→  const svgRef = useRef<SVGSVGElement>(null);
 33→
 34→  const filled = useMemo(() => fillDateGaps(data), [data]);
 35→  const grouped = useMemo(
 36→    () => groupDailyStats(filled, timeGroup),
 37→    [filled, timeGroup]
 38→  );
 39→
 40→  const values = useMemo(() => {
 41→    return grouped.map((d) => {
 42→      switch (metric) {
 43→        case "sessions":
 44→          return d.session_count;
 45→        case "messages":
 46→          return d.total_messages;
 47→        case "tokens":
 48→          return d.total_tokens;
 49→        case "cost":
 50→          return d.total_cost_usd;
 51→      }
 52→    });
 53→  }, [grouped, metric]);
 54→
 55→  const maxVal = Math.max(1, ...values);
 56→  const isSinglePoint = grouped.length === 1;
 57→
 58→  const points = useMemo(
 59→    () =>
 60→      values.map((v, i) => ({
 61→        x:
 62→          ML +
 63→          (grouped.length > 1 ? (i / (grouped.length - 1)) * PW : PW / 2),
 64→        y: MT + PH - (v / maxVal) * PH,
 65→      })),
 66→    [values, maxVal, grouped.length]
 67→  );
 68→
 69→  const lineD = points
 70→    .map((p, i) => `${i === 0 ? "M" : "L"}${p.x},${p.y}`)
 71→    .join(" ");
 72→  const areaD =
 73→    lineD +
 74→    ` L${points[points.length - 1].x},${MT + PH} L${points[0].x},${MT + PH} Z`;
 75→
 76→  const gridFractions = [0.25, 0.5, 0.75, 1];
 77→  const gridLines = gridFractions.map((f) => MT + PH * (1 - f));
 78→
 79→  const formatY = (val: number) => {
 80→    if (metric === "tokens") return formatTokens(val);
 81→    if (metric === "cost") return formatCost(val);
 82→    return String(Math.round(val));
 83→  };
 84→
 85→  const labelInterval = Math.max(1, Math.ceil(grouped.length / 7));
 86→
 87→  const formatXLabel = (date: string) => {
 88→    if (timeGroup === "year") return date;
 89→    if (timeGroup === "month") return date;
 90→    return date.slice(5);
 91→  };
 92→
 93→  const findNearestIndex = useCallback(
 94→    (clientX: number): number | null => {
 95→      const svg = svgRef.current;
 96→      if (!svg || points.length === 0) return null;
 97→      const rect = svg.getBoundingClientRect();
 98→      const svgX = ((clientX - rect.left) / rect.width) * W;
 99→
100→      let nearest = 0;
101→      let minDist = Math.abs(svgX - points[0].x);
102→      for (let i = 1; i < points.length; i++) {
103→        const dist = Math.abs(svgX - points[i].x);
104→        if (dist < minDist) {
105→          minDist = dist;
106→          nearest = i;
107→        }
108→      }
109→      return nearest;
110→    },
111→    [points]
112→  );
113→
114→  const handleMouseMove = useCallback(
115→    (e: React.MouseEvent) => {
116→      const idx = findNearestIndex(e.clientX);
117→      if (idx === null) return;
118→      setActiveIndex(idx);
119→      const d = grouped[idx];
120→      const lines = [
121→        d.date,
122→        `Sessions: ${d.session_count}`,
123→        `Messages: ${d.total_messages.toLocaleString()}`,
124→        `Tokens: ${d.total_tokens.toLocaleString()}`,
125→        `Cost: ${formatCost(d.total_cost_usd)}`,
126→      ];
127→      onHover(e, lines.join("\n"));
128→      onMove(e);
129→    },
130→    [findNearestIndex, grouped, onHover, onMove]
131→  );
132→
133→  const handleMouseLeave = useCallback(() => {
134→    setActiveIndex(null);
135→    onLeave();
136→  }, [onLeave]);
137→
138→  const metricButtons: Array<{ key: ChartMetric; label: string }> = [
139→    { key: "sessions", label: "Sessions" },
140→    { key: "messages", label: "Messages" },
141→    { key: "tokens", label: "Tokens" },
142→    { key: "cost", label: "Cost" },
143→  ];
144→
145→  const timeGroupButtons: Array<{ key: TimeGroup; label: string }> = [
146→    { key: "day", label: "Day" },
147→    { key: "month", label: "Month" },
148→    { key: "year", label: "Year" },
149→  ];
150→
151→  if (grouped.length < 1) {
152→    return (
153→      <div>
154→        <h3 className="text-base font-medium text-zinc-200 mb-3">
155→          Usage Over Time
156→        </h3>
157→        <p className="text-sm text-zinc-400 py-8 text-center">
158→          No data available
159→        </p>
160→      </div>
161→    );
162→  }
163→
164→  return (
165→    <div>
166→      <div className="flex items-center justify-between mb-3">
167→        <h3 className="text-base font-medium text-zinc-200">
168→          Usage Over Time
169→        </h3>
170→        <div className="flex items-center gap-3">
171→          <div className="flex gap-1">
172→            {timeGroupButtons.map((g) => (
173→              <button
174→                key={g.key}
175→                onClick={() => setTimeGroup(g.key)}
176→                className={`px-2 py-1 text-xs font-medium rounded-md transition ${
177→                  timeGroup === g.key
178→                    ? "bg-zinc-700 text-zinc-100"
179→                    : "text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800"
180→                }`}
181→              >
182→                {g.label}
183→              </button>
184→            ))}
185→          </div>
186→          <div className="w-px h-4 bg-zinc-700" />
187→          <div className="flex gap-1">
188→            {metricButtons.map((m) => (
189→              <button
190→                key={m.key}
191→                onClick={() => setMetric(m.key)}
192→                className={`px-2.5 py-1 text-xs font-medium rounded-md transition ${
193→                  metric === m.key
194→                    ? "bg-cyan-600 text-white"
195→                    : "text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800"
196→                }`}
197→              >
198→                {m.label}
199→              </button>
200→            ))}
201→          </div>
202→        </div>
203→      </div>
204→      <svg
205→        ref={svgRef}
206→        viewBox={`0 0 ${W} ${H}`}
207→        className="w-full"
208→        preserveAspectRatio="xMidYMid meet"
209→      >
210→        <defs>
211→          <linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1">
212→            <stop offset="0%" stopColor="rgba(34,211,238,0.3)" />
213→            <stop offset="100%" stopColor="rgba(34,211,238,0.02)" />
214→          </linearGradient>
215→        </defs>
216→
217→        {gridLines.map((y, i) => (
218→          <g key={i}>
219→            <line
220→              x1={ML}
221→              y1={y}
222→              x2={W - MR}
223→              y2={y}
224→              stroke="rgba(255,255,255,0.06)"
225→            />
226→            <text
227→              x={ML - 8}
228→              y={y + 4}
229→              fill="#a1a1aa"
230→              fontSize={10}
231→              textAnchor="end"
232→            >
233→              {formatY(maxVal * gridFractions[i])}
234→            </text>
235→          </g>
236→        ))}
237→
238→        <line
239→          x1={ML}
240→          y1={MT + PH}
241→          x2={W - MR}
242→          y2={MT + PH}
243→          stroke="rgba(255,255,255,0.08)"
244→        />
245→
246→        {isSinglePoint ? (
247→          <rect
248→            x={points[0].x - 30}
249→            y={points[0].y}
250→            width={60}
251→            height={MT + PH - points[0].y}
252→            fill="url(#areaGrad)"
253→            stroke="rgb(34,211,238)"
254→            strokeWidth={2}
255→            rx={4}
256→          />
257→        ) : (
258→          <>
259→            <path d={areaD} fill="url(#areaGrad)" />
260→            <path
261→              d={lineD}
262→              fill="none"
263→              stroke="rgb(34,211,238)"
264→              strokeWidth={2}
265→            />
266→          </>
267→        )}
268→
269→        {/* Small dots on each data point */}
270→        {!isSinglePoint &&
271→          points.map((p, i) => (
272→            <circle
273→              key={i}
274→              cx={p.x}
275→              cy={p.y}
276→              r={activeIndex === i ? 5 : 3}
277→              fill="rgb(34,211,238)"
278→              className="pointer-events-none transition-all"
279→            />
280→          ))}
281→
282→        {/* Vertical crosshair line at active point */}
283→        {activeIndex !== null && points[activeIndex] && (
284→          <line
285→            x1={points[activeIndex].x}
286→            y1={MT}
287→            x2={points[activeIndex].x}
288→            y2={MT + PH}
289→            stroke="rgba(34,211,238,0.4)"
290→            strokeWidth={1}
291→            strokeDasharray="4 3"
292→            className="pointer-events-none"
293→          />
294→        )}
295→
296→        {/* Invisible overlay for mouse tracking across entire chart area */}
297→        <rect
298→          x={ML}
299→          y={MT}
300→          width={PW}
301→          height={PH}
302→          fill="transparent"
303→          className="cursor-crosshair"
304→          onMouseMove={handleMouseMove}
305→          onMouseLeave={handleMouseLeave}
306→        />
307→
308→        {grouped.map((d, i) => {
309→          if (i % labelInterval !== 0 && i !== grouped.length - 1) return null;
310→          return (
311→            <text
312→              key={d.date}
313→              x={points[i].x}
314→              y={H - 6}
315→              fill="#a1a1aa"
316→              fontSize={10}
317→              textAnchor="middle"
318→            >
319→              {formatXLabel(d.date)}
320→            </text>
321→          );
322→        })}
323→      </svg>
324→    </div>
325→  );
326→}
