 28→export function ActivityHeatmap({
 29→  data,
 30→  onHover,
 31→  onMove,
 32→  onLeave,
 33→}: ActivityHeatmapProps) {
 34→  const { weeks, monthLabels, maxVal, yearTotal } = useMemo(() => {
 35→    const today = new Date();
 36→    const weeksData: Array<
 37→      Array<{ date: string; count: number; dayOfWeek: number }>
 38→    > = [];
 39→    const labels: Array<{ month: string; weekIndex: number }> = [];
 40→
 41→    // Monday of the current week, then back (HEATMAP_WEEKS - 1) full weeks
 42→    const daysToMonday = (today.getDay() + 6) % 7;
 43→    const startDate = new Date(today);
 44→    startDate.setDate(today.getDate() - daysToMonday - (HEATMAP_WEEKS - 1) * 7);
 45→
 46→    let lastMonth = -1;
 47→    let total = 0;
 48→    for (let w = 0; w < HEATMAP_WEEKS; w++) {
 49→      const week: Array<{
 50→        date: string;
 51→        count: number;
 52→        dayOfWeek: number;
 53→      }> = [];
 54→      for (let d = 0; d < 7; d++) {
 55→        const current = new Date(startDate);
 56→        current.setDate(startDate.getDate() + w * 7 + d);
 57→        if (current > today) {
 58→          week.push({ date: "", count: 0, dayOfWeek: d });
 59→          continue;
 60→        }
 61→        const dateStr = toLocalDateStr(current);
 62→        const count = data[dateStr] || 0;
 63→        total += count;
 64→        week.push({ date: dateStr, count, dayOfWeek: d });
 65→
 66→        if (d === 0 && current.getMonth() !== lastMonth) {
 67→          lastMonth = current.getMonth();
 68→          labels.push({ month: MONTH_NAMES[lastMonth], weekIndex: w });
 69→        }
 70→      }
 71→      weeksData.push(week);
 72→    }
 73→
 74→    const allCounts = Object.values(data);
 75→    const max = Math.max(1, ...allCounts);
 76→
 77→    return { weeks: weeksData, monthLabels: labels, maxVal: max, yearTotal: total };
 78→  }, [data]);
 79→
 80→  const width = LABEL_WIDTH + HEATMAP_WEEKS * (CELL_SIZE + CELL_GAP) + 10;
 81→  const height = HEADER_HEIGHT + 7 * (CELL_SIZE + CELL_GAP) + 10;
 82→
 83→  const formatDate = (dateStr: string) => {
 84→    if (!dateStr) return "";
 85→    const d = new Date(dateStr + "T00:00:00");
 86→    const days = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
 87→    const months = [
 88→      "Jan", "Feb", "Mar", "Apr", "May", "Jun",
 89→      "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
 90→    ];
 91→    return `${days[d.getDay()]}, ${months[d.getMonth()]} ${d.getDate()}, ${d.getFullYear()}`;
 92→  };
 93→
 94→  return (
 95→    <div>
 96→      <div className="flex items-center justify-between mb-3">
 97→        <p
 98→          className="text-[13px] text-zinc-300 cursor-default"
 99→          onMouseEnter={(e) =>
100→            onHover(e, "GitHub-style heatmap showing daily session activity over the past year")
101→          }
102→          onMouseMove={onMove}
103→          onMouseLeave={onLeave}
104→        >
105→          <span className="text-cyan-400 font-semibold">
106→            {yearTotal.toLocaleString()}
107→          </span>{" "}
108→          sessions in the last year
109→        </p>
110→        <div className="flex items-center gap-1.5 text-xs text-zinc-400">
111→          <span>Less</span>
112→          {HEATMAP_COLORS.slice(1).map((color, i) => (
113→            <div
114→              key={i}
115→              className="w-2.5 h-2.5 rounded-sm"
116→              style={{ backgroundColor: color }}
117→            />
118→          ))}
119→          <span>More</span>
120→        </div>
121→      </div>
122→      <div className="overflow-x-auto">
123→        <svg width={width} height={height} className="text-zinc-400">
124→          {monthLabels.map(({ month, weekIndex }, i) => (
125→            <text
126→              key={`${month}-${i}`}
127→              x={LABEL_WIDTH + weekIndex * (CELL_SIZE + CELL_GAP)}
128→              y={12}
129→              fill="currentColor"
130→              fontSize={11}
131→            >
132→              {month}
133→            </text>
134→          ))}
135→
136→          {DAY_LABELS.map(
137→            (label, dayIdx) =>
138→              label && (
139→                <text
140→                  key={label}
141→                  x={0}
142→                  y={
143→                    HEADER_HEIGHT +
144→                    dayIdx * (CELL_SIZE + CELL_GAP) +
145→                    CELL_SIZE / 2 +
146→                    4
147→                  }
148→                  fill="currentColor"
149→                  fontSize={10}
150→                >
151→                  {label}
152→                </text>
153→              )
154→          )}
155→
156→          {weeks.map((week, wIdx) =>
157→            week.map((day) =>
158→              day.date ? (
159→                <rect
160→                  key={day.date}
161→                  x={LABEL_WIDTH + wIdx * (CELL_SIZE + CELL_GAP)}
162→                  y={HEADER_HEIGHT + day.dayOfWeek * (CELL_SIZE + CELL_GAP)}
163→                  width={CELL_SIZE}
164→                  height={CELL_SIZE}
165→                  rx={2}
166→                  fill={getHeatmapColor(day.count, maxVal)}
167→                  onMouseEnter={(e) =>
168→                    onHover(
169→                      e,
170→                      `${formatDate(day.date)}\n${day.count} session${day.count !== 1 ? "s" : ""}`
171→                    )
172→                  }
173→                  onMouseMove={onMove}
174→                  onMouseLeave={onLeave}
175→                  className="cursor-default"
176→                />
177→              ) : null
178→            )
179→          )}
180→        </svg>
181→      </div>
182→    </div>
183→  );
184→}
