 31→export function SessionView({ sessionId }: SessionViewProps) {
 32→  const { fetchWithToken } = useAppContext();
 33→  const [trajectories, setTrajectories] = useState<Trajectory[]>([]);
 34→  const [loading, setLoading] = useState(true);
 35→  const [error, setError] = useState("");
 36→  const [activeStepId, setActiveStepId] = useState<string | null>(null);
 37→  const [promptNavWidth, setPromptNavWidth] = useState(224);
 38→  const [sessionCost, setSessionCost] = useState<number | null>(null);
 39→  const stepsRef = useRef<HTMLDivElement>(null);
 40→  const isNavigatingRef = useRef(false);
 41→
 42→  const MIN_PROMPT_NAV_WIDTH = 160;
 43→  const MAX_PROMPT_NAV_WIDTH = 400;
 44→
 45→  const handlePromptNavResize = useCallback((delta: number) => {
 46→    setPromptNavWidth((w) =>
 47→      Math.min(MAX_PROMPT_NAV_WIDTH, Math.max(MIN_PROMPT_NAV_WIDTH, w + delta))
 48→    );
 49→  }, []);
 50→
 51→  useEffect(() => {
 52→    setLoading(true);
 53→    setError("");
 54→    setTrajectories([]);
 55→    setActiveStepId(null);
 56→    setSessionCost(null);
 57→
 58→    fetchWithToken(`/api/sessions/${sessionId}`)
 59→      .then((res) => {
 60→        if (!res.ok) throw new Error(`Failed to load session: ${res.status}`);
 61→        return res.json();
 62→      })
 63→      .then((data: Trajectory[]) => {
 64→        setTrajectories(data);
 65→      })
 66→      .catch((err: Error) => setError(err.message))
 67→      .finally(() => setLoading(false));
 68→  }, [sessionId, fetchWithToken]);
 69→
 70→  // Fetch session analytics for cost estimation (non-blocking)
 71→  useEffect(() => {
 72→    if (!sessionId || loading) return;
 73→    fetchWithToken(`/api/analysis/sessions/${sessionId}/stats`)
 74→      .then((res) => (res.ok ? res.json() : null))
 75→      .then((data) => {
 76→        if (data?.cost_usd != null) setSessionCost(data.cost_usd);
 77→      })
 78→      .catch(() => {});
 79→  }, [sessionId, loading, fetchWithToken]);
 80→
 81→  const main = useMemo(
 82→    () => trajectories.find((t) => !t.parent_trajectory_ref) ?? trajectories[0] ?? null,
 83→    [trajectories]
 84→  );
 85→
 86→  const subAgents = useMemo(
 87→    () =>
 88→      trajectories
 89→        .filter((t) => !!t.parent_trajectory_ref)
 90→        .sort((a, b) => {
 91→          const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
 92→          const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
 93→          return ta - tb;
 94→        }),
 95→    [trajectories]
 96→  );
 97→
 98→  // Build a map: step_id -> sub-agent trajectories spawned from that step.
 99→  // Phase 1 links via observation.subagent_trajectory_ref (explicit linkage).
100→  // Phase 2 places unlinked sub-agents (e.g. compaction) at the
101→  // chronologically correct position using timestamp heuristics.
102→  const subAgentsByStep = useMemo(() => {
103→    const map = new Map<string, Trajectory[]>();
104→    const orphans: Trajectory[] = [];
105→    const unlinked: Trajectory[] = [];
106→
107→    for (const sub of subAgents) {
108→      let placed = false;
109→      if (main?.steps) {
110→        for (const step of main.steps) {
111→          if (!step.observation) continue;
112→          for (const result of step.observation.results) {
113→            if (!result.subagent_trajectory_ref) continue;
114→            for (const ref of result.subagent_trajectory_ref) {
115→              if (ref.session_id === sub.session_id) {
116→                const existing = map.get(step.step_id) || [];
117→                existing.push(sub);
118→                map.set(step.step_id, existing);
119→                placed = true;
120→                break;
121→              }
122→            }
123→            if (placed) break;
124→          }
125→          if (placed) break;
126→        }
127→      }
128→      if (!placed) unlinked.push(sub);
129→    }
130→
131→    // Place unlinked sub-agents at the last main step whose timestamp
132→    // is <= the sub-agent's start timestamp. Falls back to orphans
133→    // only when no timestamp is available.
134→    for (const sub of unlinked) {
135→      const subTs = sub.timestamp ? new Date(sub.timestamp).getTime() : NaN;
136→      if (!isNaN(subTs) && main?.steps) {
137→        let bestStepId: string | null = null;
138→        for (const step of main.steps) {
139→          if (!step.timestamp) continue;
140→          const stepTs = new Date(step.timestamp).getTime();
141→          if (stepTs <= subTs) bestStepId = step.step_id;
142→          else break;
143→        }
144→        if (bestStepId) {
145→          const existing = map.get(bestStepId) || [];
146→          existing.push(sub);
147→          map.set(bestStepId, existing);
148→          continue;
149→        }
150→      }
151→      orphans.push(sub);
152→    }
153→
154→    return { map, orphans };
155→  }, [main, subAgents]);
156→
157→  const steps = (main?.steps || []) as Step[];
158→
159→  const userStepIds = useMemo(() => {
160→    return steps
161→      .filter((s) => s.source === "user" && extractUserText(s))
162→      .map((s) => s.step_id);
163→  }, [steps]);
164→
165→  // IntersectionObserver to track which user prompt is currently visible
166→  useEffect(() => {
167→    if (!stepsRef.current || userStepIds.length < 2) return;
168→
169→    const observer = new IntersectionObserver(
170→      (entries) => {
171→        if (isNavigatingRef.current) return;
172→        let topEntry: IntersectionObserverEntry | null = null;
173→        for (const entry of entries) {
174→          if (!entry.isIntersecting) continue;
175→          if (!topEntry || entry.boundingClientRect.top < topEntry.boundingClientRect.top) {
176→            topEntry = entry;
177→          }
178→        }
179→        if (topEntry) {
180→          setActiveStepId(topEntry.target.id.replace("step-", ""));
181→        }
182→      },
183→      {
184→        root: stepsRef.current,
185→        rootMargin: "-10% 0px -80% 0px",
186→        threshold: 0,
187→      }
188→    );
189→
190→    for (const stepId of userStepIds) {
191→      const el = document.getElementById(`step-${stepId}`);
192→      if (el) observer.observe(el);
193→    }
194→
195→    return () => observer.disconnect();
196→  }, [userStepIds]);
197→
198→  const SCROLL_SUPPRESS_MS = 800;
199→
200→  const handlePromptNavigate = useCallback((stepId: string) => {
201→    const el = document.getElementById(`step-${stepId}`);
202→    if (!el) return;
203→    isNavigatingRef.current = true;
204→    setActiveStepId(stepId);
205→    el.scrollIntoView({ behavior: "smooth", block: "start" });
206→    setTimeout(() => {
207→      isNavigatingRef.current = false;
208→    }, SCROLL_SUPPRESS_MS);
209→  }, []);
210→
211→  if (loading) {
212→    return (
213→      <div className="flex items-center justify-center h-full">
214→        <div className="text-center">
215→          <Loader2 className="w-8 h-8 text-cyan-500 animate-spin mx-auto mb-2" />
216→          <p className="text-sm text-zinc-400">Loading session...</p>
217→        </div>
218→      </div>
219→    );
220→  }
221→
222→  if (error) {
223→    return (
224→      <div className="flex items-center justify-center h-full p-4">
225→        <div className="text-center bg-rose-900/20 border border-rose-800 rounded-lg p-6 max-w-md">
226→          <p className="text-sm font-semibold text-rose-300 mb-2">Failed to load session</p>
227→          <p className="text-xs text-rose-400 mb-4 font-mono break-all">{error}</p>
228→          <button
229→            onClick={() => window.location.reload()}
230→            className="px-3 py-1 bg-rose-700/50 hover:bg-rose-700 rounded text-xs text-rose-200 transition"
231→          >
232→            Retry
233→          </button>
234→        </div>
235→      </div>
236→    );
237→  }
238→
239→  if (!main) return null;
240→
241→  const metrics = main.final_metrics;
242→  const promptCount = steps.filter(
243→    (s) => s.source === "user" && !s.extra?.is_skill_output && extractUserText(s)
244→  ).length;
245→  const skillCount = steps.filter(
246→    (s) => s.source === "user" && s.extra?.is_skill_output
247→  ).length;
248→  const totalTokens =
249→    (metrics?.total_prompt_tokens || 0) +
250→    (metrics?.total_completion_tokens || 0);
251→
252→  const isVisibleStep = (s: Step): boolean => {
253→    if (s.source === "user") {
254→      if (typeof s.message === "string") return !!s.message.trim();
255→      return s.message.length > 0;
256→    }
257→    return s.source === "agent" || s.source === "system";
258→  };
259→
260→  return (
261→    <div className="h-full flex flex-col overflow-hidden">
262→      {/* Session Header */}
263→      <div className="shrink-0 bg-zinc-900/95 border-b border-zinc-800 px-6 py-4">
264→        <div className="max-w-7xl mx-auto">
265→          {/* Row 1: Title + Meta Pills */}
266→          <div className="flex items-start justify-between mb-3">
267→            <div className="min-w-0 flex-1">
268→              <div className="flex items-center gap-2">
269→                <MetaPill
270→                  icon={<Hash className="w-3 h-3" />}
271→                  label={main.session_id.slice(0, 8)}
272→                  color="text-zinc-300"
273→                  tooltip={`Session ID: ${main.session_id}`}
274→                />
275→                <h2 className="text-sm font-semibold text-zinc-100 truncate">
276→                  {main.first_message || "Session"}
277→                </h2>
278→              </div>
279→              <div className="flex flex-wrap items-center gap-1.5 mt-2">
280→                {main.agent.model_name && (
281→                  <MetaPill
282→                    icon={<Cpu className="w-3 h-3" />}
283→                    label={`${main.agent.name}@${main.agent.model_name}`}
284→                    color="text-amber-300"
285→                    tooltip="Agent model used for this session"
286→                  />
287→                )}
288→                {main.timestamp && (
289→                  <MetaPill
290→                    icon={<Calendar className="w-3 h-3" />}
291→                    label={formatCreatedTime(main.timestamp)}
292→                    color="text-zinc-200"
293→                    tooltip="Session start time"
294→                  />
295→                )}
296→                {metrics && (
297→                  <MetaPill
298→                    icon={<Clock className="w-3 h-3" />}
299→                    label={formatDuration(metrics.duration)}
300→                    color="text-cyan-400"
