 3→
 4→export type ChartMetric = "sessions" | "messages" | "tokens" | "cost";
 5→export type TimeGroup = "day" | "month" | "year";
 6→
 7→export function fillDateGaps(data: DailyStat[]): DailyStat[] {
 8→  if (data.length < 2) return data;
 9→  const sorted = [...data].sort((a, b) => a.date.localeCompare(b.date));
10→  const result: DailyStat[] = [];
11→  const start = new Date(sorted[0].date + "T00:00:00");
12→  const end = new Date(sorted[sorted.length - 1].date + "T00:00:00");
13→  const dataMap = new Map(sorted.map((d) => [d.date, d]));
14→
15→  for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
16→    const key = d.toISOString().slice(0, 10);
17→    result.push(
18→      dataMap.get(key) || {
19→        date: key,
20→        session_count: 0,
21→        total_messages: 0,
22→        total_tokens: 0,
23→        total_duration: 0,
24→        total_duration_hours: 0,
25→        total_cost_usd: 0,
26→      }
27→    );
28→  }
29→  return result;
30→}
31→
32→export function groupDailyStats(data: DailyStat[], group: TimeGroup): DailyStat[] {
33→  if (group === "day") return data;
34→
35→  const buckets = new Map<string, DailyStat>();
36→  for (const d of data) {
37→    const key = group === "month" ? d.date.slice(0, 7) : d.date.slice(0, 4);
38→    const existing = buckets.get(key);
39→    if (existing) {
40→      existing.session_count += d.session_count;
41→      existing.total_messages += d.total_messages;
42→      existing.total_tokens += d.total_tokens;
43→      existing.total_duration += d.total_duration;
44→      existing.total_duration_hours += d.total_duration_hours;
45→      existing.total_cost_usd += d.total_cost_usd;
46→    } else {
47→      buckets.set(key, { ...d, date: key });
48→    }
49→  }
50→  return [...buckets.values()].sort((a, b) => a.date.localeCompare(b.date));
51→}
52→
53→export function displayModelName(name: string): string {
54→  if (name === "unknown") return "Unknown";
55→  return name;
56→}
57→
58→export function getHeatmapColor(count: number, maxVal: number): string {
59→  if (count === 0) return HEATMAP_COLORS[0];
60→  const ratio = count / maxVal;
61→  if (ratio <= 0.25) return HEATMAP_COLORS[1];
62→  if (ratio <= 0.5) return HEATMAP_COLORS[2];
63→  if (ratio <= 0.75) return HEATMAP_COLORS[3];
64→  return HEATMAP_COLORS[4];
65→}
