import type { ReactNode } from "react";
import type { Step } from "../../types";
import { formatElapsed, formatStepTime, formatFullDateTime } from "../../utils";

interface TimelineEntry {
  step: Step;
  content: ReactNode;
}

interface StepTimelineProps {
  entries: TimelineEntry[];
  sessionStartMs: number | null;
  sessionStartTimestamp?: string | null;
}

export function StepTimeline({
  entries,
  sessionStartMs,
  sessionStartTimestamp,
}: StepTimelineProps) {
  const hasTimestamps = entries.some((e) => e.step.timestamp);
  if (!hasTimestamps) {
    return (
      <>
        {entries.map((entry) => (
          <div key={entry.step.step_id}>{entry.content}</div>
        ))}
      </>
    );
  }

  const startMs =
    sessionStartMs ?? findFirstTimestampMs(entries.map((e) => e.step));

  return (
    <>
      {entries.map((entry, index) => {
        const stepMs = entry.step.timestamp
          ? new Date(entry.step.timestamp).getTime()
          : null;
        const elapsedSeconds =
          startMs != null && stepMs != null
            ? Math.max(0, Math.floor((stepMs - startMs) / 1000))
            : null;

        const prevEntry = entries[index - 1];
        const prevMs = prevEntry?.step.timestamp
          ? new Date(prevEntry.step.timestamp).getTime()
          : null;
        const gapSeconds =
          prevMs != null && stepMs != null
            ? Math.max(0, Math.floor((stepMs - prevMs) / 1000))
            : null;

        const hasNext = index < entries.length - 1;
        const isFirst = index === 0;
        const dotColor =
          entry.step.source === "user"
            ? entry.step.extra?.is_skill_output
              ? "bg-amber-500"
              : "bg-indigo-500"
            : entry.step.source === "system"
              ? "bg-zinc-500"
              : "bg-cyan-500";

        const actualTime = entry.step.timestamp
          ? formatStepTime(entry.step.timestamp, sessionStartTimestamp)
          : "";
        const fullDateTime = entry.step.timestamp
          ? formatFullDateTime(entry.step.timestamp)
          : "";

        return (
          <div key={entry.step.step_id} className="flex gap-3">
            {/* Narrow rail: dot + connector */}
            <div className="flex flex-col items-center w-5 shrink-0">
              <div
                className={`w-2 h-2 rounded-full ${dotColor} mt-[7px] shrink-0`}
              />
              {hasNext && (
                <div className="w-px flex-1 bg-zinc-700/40 min-h-[16px]" />
              )}
            </div>

            {/* Content with inline time header */}
            <div
              className={`flex-1 min-w-0 pb-5 ${!isFirst ? "border-t border-zinc-700/40 pt-3" : ""}`}
            >
              <div
                className="flex items-baseline gap-1.5 mb-1.5 cursor-default"
                title={fullDateTime}
              >
                {elapsedSeconds != null && (
                  <span className="text-xs font-mono text-zinc-400">
                    {formatElapsed(elapsedSeconds)}
                  </span>
                )}
                {actualTime && (
                  <>
                    <span className="text-zinc-600 text-[11px]">&middot;</span>
                    <span className="text-[11px] font-mono text-zinc-500">
                      {actualTime}
                    </span>
                  </>
                )}
                {gapSeconds != null && gapSeconds > 0 && (
                  <span className="text-[10px] font-mono text-zinc-600 ml-auto">
                    +{formatElapsed(gapSeconds)}
                  </span>
                )}
              </div>
              {entry.content}
            </div>
          </div>
        );
      })}
    </>
  );
}

function findFirstTimestampMs(steps: Step[]): number | null {
  for (const step of steps) {
    if (step.timestamp) {
      const ms = new Date(step.timestamp).getTime();
      if (!isNaN(ms)) return ms;
    }
  }
  return null;
}

"""Per-session detailed analytics computation.

Computes token breakdowns, tool frequency, step counts, phase segments,
and cost estimation for a single session (main trajectory + sub-agents).
"""

from collections import defaultdict

from vibelens.analysis.phase_detector import detect_phases
from vibelens.analysis.pricing import compute_trajectory_cost
from vibelens.models.analysis.dashboard import SessionAnalytics
from vibelens.models.trajectories import Trajectory


def compute_session_analytics(trajectories: list[Trajectory]) -> SessionAnalytics:
    """Compute detailed analytics for a single session.

    Args:
        trajectories: Trajectory group for one session (main + sub-agents).

    Returns:
        SessionAnalytics with token breakdown, tool frequency, and phase segments.
    """
    if not trajectories:
        raise ValueError("No trajectories provided for session analytics")

    main = trajectories[0]
    all_steps = []
    for traj in trajectories:
        all_steps.extend(traj.steps)

    total_cost = 0.0
    has_cost = False
    for traj in trajectories:
        traj_cost = compute_trajectory_cost(traj)
        if traj_cost is not None:
            total_cost += traj_cost
            has_cost = True

    return SessionAnalytics(
        session_id=main.session_id,
        token_breakdown=_compute_token_breakdown(trajectories),
        tool_frequency=_compute_tool_frequency(trajectories),
        step_count_by_source=_compute_step_counts(trajectories),
        phase_segments=detect_phases(all_steps),
        cost_usd=round(total_cost, 6) if has_cost else None,
    )


def _compute_token_breakdown(trajectories: list[Trajectory]) -> dict[str, int]:
    """Aggregate token counts by category across all trajectories."""
    prompt = 0
    completion = 0
    cache_read = 0
    cache_write = 0

    for traj in trajectories:
        for step in traj.steps:
            if step.metrics:
                prompt += step.metrics.prompt_tokens
                completion += step.metrics.completion_tokens
                cache_read += step.metrics.cached_tokens
                cache_write += step.metrics.cache_creation_tokens

    return {
        "prompt": prompt,
        "completion": completion,
        "cache_read": cache_read,
        "cache_write": cache_write,
    }


def _compute_tool_frequency(trajectories: list[Trajectory]) -> dict[str, int]:
    """Count tool calls by function name across all trajectories."""
    counts: dict[str, int] = defaultdict(int)
    for traj in trajectories:
        for step in traj.steps:
            for tc in step.tool_calls:
                counts[tc.function_name] += 1
    return dict(sorted(counts.items(), key=lambda x: x[1], reverse=True))


def _compute_step_counts(trajectories: list[Trajectory]) -> dict[str, int]:
    """Count steps by source (user/agent/system) across all trajectories."""
    counts: dict[str, int] = defaultdict(int)
    for traj in trajectories:
        for step in traj.steps:
            counts[step.source.value] += 1
    return dict(counts)

